parameters.blocksUi:
={
  "blocks": [
    {
      "type": "header",
      "text": {
        "type": "plain_text",
        "text": "🔥 New ChatSyncs Lead",
        "emoji": true
      }
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "<@U08MP7Z8215> New lead from the pricing page!"
      }
    },
    {
      "type": "divider"
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Name:*  {{ $json.body.fullName }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Company:*  {{ $json.body.companyName }}"
        }
      ]
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*WhatsApp:*  {{ $json.body.whatsappE164 }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Email:*  {{ $json.body.emailId || 'Not provided' }}"
        }
      ]
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Industry:*  {{ $json.body.industry.label }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Daily conversations:*  {{ $json.body.dailyConversations.label }}"
        }
      ]
    },
    {
      "type": "divider"
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Wants to automate:*  {{ $json.body.automationGoals.map(g => g.label).join(', ') }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Lead sources:*  {{ $json.body.leadSources.map(s => s.label).join(', ') }}"
        }
      ]
    },
    {
      "type": "divider"
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Current tool:*  {{ $json.body.whatsappTool.label }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Timeline:*  {{ $json.body.startTimeline.label }}"
        }
      ]
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*Notes:*  {{ ($json.body.notes || 'None').replace(/[\\r\\n]+/g, ' ').trim() }}"
      }
    },
    {
      "type": "divider"
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Submitted:*  {{ DateTime.fromISO($json.body.submittedAt).setZone('Asia/Kolkata').toFormat('dd MMM yyyy, hh:mm a') }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Page:*  {{ $json.body.pagePath }}"
        }
      ]
    },
    {
      "type": "context",
      "elements": [
        {
          "type": "mrkdwn",
          "text": "ChatSyncs Lead Form | n8n automation"
        }
      ]
    }
  ]
}
